/** @odoo-module **/

import { Component, useState, onWillStart } from "@odoo/owl";
import { registry } from "@web/core/registry";
import { useService } from "@web/core/utils/hooks";

/**
 * TaskTracker OWL Component
 * Renders inside the Odoo webclient as a client action.
 * Shows live task count fetched via ORM service.
 *
 * Generated by create-odoo-module (https://create-odoo-module.dev)
 */
class TaskTrackerWidget extends Component {
    static template = `
        <div class="task_tracker-widget o_nocontent_help">
            <div class="o_empty_folder_image"/>
            <p class="o_view_nocontent_smiling_face">
                Task Tracker Dashboard
            </p>
            <p>
                Total records: <strong>{{ state.count }}</strong>
            </p>
            <p>
                Draft: <strong>{{ state.draft }}</strong> |
                In Progress: <strong>{{ state.in_progress }}</strong> |
                Done: <strong>{{ state.done }}</strong>
            </p>
        </div>
    `;

    setup() {
        this.orm   = useService("orm");
        this.state = useState({
            count:       0,
            draft:       0,
            in_progress: 0,
            done:        0,
        });

        onWillStart(async () => {
            const [count, draft, in_progress, done] = await Promise.all([
                this.orm.searchCount("task.tracker", []),
                this.orm.searchCount("task.tracker", [["state", "=", "draft"]]),
                this.orm.searchCount("task.tracker", [["state", "=", "in_progress"]]),
                this.orm.searchCount("task.tracker", [["state", "=", "done"]]),
            ]);
            Object.assign(this.state, { count, draft, in_progress, done });
        });
    }
}

// Register as a client action — can be opened via ir.actions.client
registry.category("actions").add("task_tracker_action_widget", TaskTrackerWidget);
